  1	import * as React from 'react';
  2	import classNames from 'classnames';
  3	import { useTranslation } from 'react-i18next';
  4	import { DomainPropType, DomainTuple } from 'victory-core';
  5	import {
  6	  Chart,
  7	  ChartAxis,
  8	  ChartAxisProps,
  9	  ChartDonut,
 10	  ChartGroup,
 11	  ChartLabel,
 12	  ChartLegend,
 13	  ChartLine,
 14	  ChartVoronoiContainer,
 15	} from '@patternfly/react-charts';
 16	import {
 17	  Alert,
 18	  Card,
 19	  CardBody,
 20	  CardTitle,
 21	  Grid,
 22	  GridItem,
 23	  Popover,
 24	} from '@patternfly/react-core';
 25	import { chart_color_black_200 as othersColor } from '@patternfly/react-tokens/dist/js/chart_color_black_200';
 26	import { chart_color_black_500 as cancelledColor } from '@patternfly/react-tokens/dist/js/chart_color_black_500';
 27	import { chart_color_green_400 as successColor } from '@patternfly/react-tokens/dist/js/chart_color_green_400';
 28	import { t_global_color_status_danger_default as failureColor } from '@patternfly/react-tokens/dist/js/t_global_color_status_danger_default';
 29	import { chart_color_blue_300 as runningColor } from '@patternfly/react-tokens/dist/js/chart_color_blue_300';
 30	import { useFlag } from '@openshift-console/dynamic-plugin-sdk';
 31	import {
 32	  formatDate,
 33	  getDropDownDate,
 34	  getXaxisValues,
 35	  hourformat,
 36	  parsePrometheusDuration,
 37	  monthYear,
 38	} from './dateTime';
 39	import { getFilter, useInterval } from './utils';
 40	import { getResultsSummary } from '../utils/summary-api';
 41	import './PipelinesOverview.scss';
 42	import { LoadingInline } from '../Loading';
 43	import { ALL_NAMESPACES_KEY } from '../../consts';
 44	import { DataType, FLAGS, SummaryResponse } from '../../types';
 45	import { OutlinedQuestionCircleIcon } from '@patternfly/react-icons';
 46	
 47	interface PipelinesRunsStatusCardProps {
 48	  timespan?: number;
 49	  domain?: DomainPropType;
 50	  bordered?: boolean;
 51	  namespace: string;
 52	  interval: number;
 53	  kind?: string;
 54	  parentName?: string;
 55	}
 56	
 57	type DomainType = { x?: DomainTuple; y?: DomainTuple };
 58	
 59	const getChartData = (
 60	  tickValues: number[] | Date[],
 61	  data: SummaryResponse,
 62	  key: string,
 63	  type: string,
 64	): {
 65	  x: number;
 66	  y: number;
 67	  name: string;
 68	}[] => {
 69	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 70	  const k = key.toLowerCase();
 71	  const chartData = tickValues?.map((value) => {
 72	    const s = data?.summary?.find((d) => {
 73	      const group_date = new Date(Number(d.group_value) * 1000);
 74	      if (type == 'hour') {
 75	        return group_date.getHours() === value;
 76	      }
 77	      if (type == 'day' || type == 'week') {
 78	        return group_date.toDateString() === new Date(value).toDateString();
 79	      }
 80	      if (type == 'month') {
 81	        return group_date.getMonth() === value.getMonth();
 82	      }
 83	    });
 84	    return {
 85	      x: value,
 86	      y: Math.round((100 * s?.[k]) / s?.total) || 0,
 87	      name: t(key),
 88	    };
 89	  });
 90	  return chartData;
 91	};
 92	
 93	const PipelinesRunsStatusCard: React.FC<PipelinesRunsStatusCardProps> = ({
 94	  timespan,
 95	  domain,
 96	  bordered,
 97	  namespace,
 98	  interval,
 99	  parentName,
100	  kind,
101	}) => {
102	  const { t } = useTranslation('plugin__pipelines-console-plugin');
103	  const isDevConsoleProxyAvailable = useFlag(FLAGS.DEVCONSOLE_PROXY);
104	  const [data, setData] = React.useState<SummaryResponse>();
105	  const [data2, setData2] = React.useState<SummaryResponse>();
106	  const [loaded, setLoaded] = React.useState(false);
107	  const [pipelineRunsStatusError, setPipelineRunsStatusError] = React.useState<
108	    string | undefined
109	  >();
110	  const abortControllerRefDonut = React.useRef<AbortController>();
111	  const abortControllerRefLineChart = React.useRef<AbortController>();
112	
113	  const startTimespan = timespan - parsePrometheusDuration('1d');
114	  const endDate = new Date(Date.now()).setHours(0, 0, 0, 0);
115	  const startDate = new Date(Date.now() - startTimespan).setHours(0, 0, 0, 0);
116	  const { x: domainX, y: domainY } = (domain as DomainType) || {};
117	  const domainValue: DomainPropType = {
118	    x: domainX || [startDate, endDate],
119	    y: domainY || undefined,
120	  };
121	  const date = getDropDownDate(timespan).toISOString();
122	
123	  if (namespace == ALL_NAMESPACES_KEY) {
124	    namespace = '-';
125	  }
126	
127	  React.useEffect(() => {
128	    return () => {
129	      abortControllerRefDonut.current?.abort();
130	      abortControllerRefLineChart.current?.abort();
131	    };
132	  }, []);
133	
134	  const getSummaryData = (summary, setData, groupBy?, controller?) => {
135	    // Clear stale data before making new request
136	    setData(undefined);
137	
138	    const summaryOpt = {
139	      summary,
140	      filter: getFilter(date, parentName, kind),
141	      data_type: DataType?.PipelineRun,
142	    };
143	    groupBy && (summaryOpt['groupBy'] = groupBy);
144	    setPipelineRunsStatusError(undefined);
145	    setLoaded(false);
146	    getResultsSummary(
147	      namespace,
148	      summaryOpt,
149	      undefined,
150	      isDevConsoleProxyAvailable,
151	      controller?.signal,
152	      90000,
153	    )
154	      .then((d) => {
155	        setLoaded(true);
156	        setPipelineRunsStatusError(undefined);
157	        setData(d);
158	      })
159	      .catch((e) => {
160	        if (e.name === 'AbortError') {
161	          // Request was cancelled, this is expected behavior
162	          return;
163	        }
164	        // Don't log to console, just show user-facing error
165	        setLoaded(true);
166	        setPipelineRunsStatusError(
167	          e.message || t('Failed to load pipeline run status data'),
168	        );
169	        // Clear stale data on error
170	        setData(undefined);
171	      });
172	  };
173	
174	  useInterval(
175	    () => {
176	      abortControllerRefDonut.current?.abort();
177	      abortControllerRefDonut.current = new AbortController();
178	      getSummaryData(
179	        'succeeded,cancelled,failed,others,running,total',
180	        setData,
181	        undefined,
182	        abortControllerRefDonut.current,
183	      );
184	    },
185	    interval,
186	    namespace,
187	    date,
188	  );
189	  React.useEffect(() => {
190	    setLoaded(false);
191	    setPipelineRunsStatusError(undefined);
192	    // Clear stale data when namespace or timespan changes
193	    setData(undefined);
194	    setData2(undefined);
195	  }, [namespace, timespan]);
196	  const [tickValues, type] = getXaxisValues(timespan);
197	
198	  let xTickFormat;
199	  let dayLabel;
200	  let showLabel = false;
201	  let chartDataSucceeded = [];
202	  let chartDataFailed = [];
203	  let chartDataCancelled = [];
204	  let chartDataOthers = [];
205	  switch (type) {
206	    case 'hour':
207	      xTickFormat = (d) => hourformat(d);
208	      showLabel = true;
209	      domainValue.x = [0, 23];
210	      useInterval(
211	        () => {
212	          abortControllerRefLineChart.current?.abort();
213	          abortControllerRefLineChart.current = new AbortController();
214	          getSummaryData(
215	            'succeeded,cancelled,failed,others,total',
216	            setData2,
217	            'hour',
218	            abortControllerRefLineChart.current,
219	          );
220	        },
221	        interval,
222	        namespace,
223	        date,
224	      );
225	      dayLabel = formatDate(new Date());
226	      chartDataSucceeded = getChartData(tickValues, data2, 'Succeeded', 'hour');
227	      chartDataFailed = getChartData(tickValues, data2, 'Failed', 'hour');
228	      chartDataCancelled = getChartData(tickValues, data2, 'Cancelled', 'hour');
229	      chartDataOthers = getChartData(tickValues, data2, 'Others', 'hour');
230	      break;
231	    case 'day':
232	      xTickFormat = (d) => formatDate(d);
233	      domainValue.x = [startDate, endDate];
234	      useInterval(
235	        () => {
236	          abortControllerRefLineChart.current?.abort();
237	          abortControllerRefLineChart.current = new AbortController();
238	          getSummaryData(
239	            'succeeded,cancelled,failed,others,total',
240	            setData2,
241	            'day',
242	            abortControllerRefLineChart.current,
243	          );
244	        },
245	        interval,
246	        namespace,
247	        date,
248	      );
249	
250	      chartDataSucceeded = getChartData(tickValues, data2, 'Succeeded', 'day');
251	      chartDataFailed = getChartData(tickValues, data2, 'Failed', 'day');
252	      chartDataCancelled = getChartData(tickValues, data2, 'Cancelled', 'day');
253	      chartDataOthers = getChartData(tickValues, data2, 'Others', 'day');
254	      break;
255	    case 'week':
256	      xTickFormat = (d) => formatDate(d);
257	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
258	      useInterval(
259	        () => {
260	          abortControllerRefLineChart.current?.abort();
261	          abortControllerRefLineChart.current = new AbortController();
262	          getSummaryData(
263	            'succeeded,cancelled,failed,others,total',
264	            setData2,
265	            'week',
266	            abortControllerRefLineChart.current,
267	          );
268	        },
269	        interval,
270	        namespace,
271	        date,
272	      );
273	
274	      chartDataSucceeded = getChartData(tickValues, data2, 'Succeeded', 'week');
275	      chartDataFailed = getChartData(tickValues, data2, 'Failed', 'week');
276	      chartDataCancelled = getChartData(tickValues, data2, 'Cancelled', 'week');
277	      chartDataOthers = getChartData(tickValues, data2, 'Others', 'week');
278	      break;
279	    case 'month':
280	      xTickFormat = (d) => monthYear(d);
281	      domainValue.x = [new Date(tickValues[0]), new Date(tickValues[11])];
282	      useInterval(
283	        () => {
284	          abortControllerRefLineChart.current?.abort();
285	          abortControllerRefLineChart.current = new AbortController();
286	          getSummaryData(
287	            'succeeded,cancelled,failed,others,total',
288	            setData2,
289	            'month',
290	            abortControllerRefLineChart.current,
291	          );
292	        },
293	        interval,
294	        namespace,
295	        date,
296	      );
297	
298	      chartDataSucceeded = getChartData(
299	        tickValues,
300	        data2,
301	        'Succeeded',
302	        'month',
303	      );
304	      chartDataFailed = getChartData(tickValues, data2, 'Failed', 'month');
305	      chartDataCancelled = getChartData(
306	        tickValues,
307	        data2,
308	        'Cancelled',
309	        'month',
310	      );
311	      chartDataOthers = getChartData(tickValues, data2, 'Others', 'month');
312	      break;
313	    default:
314	      console.log('Received wrong data');
315	      break;
316	  }
317	
318	  let xAxisStyle: ChartAxisProps['style'] = {
319	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)' },
320	  };
321	  const yAxisStyle: ChartAxisProps['style'] = {
322	    tickLabels: { fill: 'var(--pf-t--global--text--color--regular)' },
323	  };
324	  if (tickValues?.length > 7) {
325	    xAxisStyle = {
326	      tickLabels: {
327	        fill: 'var(--pf-t--global--text--color--regular)',
328	        angle: 320,
329	        fontSize: 10,
330	        textAnchor: 'end',
331	        verticalAnchor: 'end',
332	      },
333	    };
334	  }
335	
336	  const colorScale = [
337	    successColor.value,
338	    failureColor.value,
339	    runningColor.value,
340	    cancelledColor.value,
341	    othersColor.value,
342	  ];
343	
344	  const colorScaleLineChart = [
345	    successColor.value,
346	    failureColor.value,
347	    cancelledColor.value,
348	    othersColor.value,
349	  ];
350	
351	  const donutData = [
352	    {
353	      x: t('Succeeded'),
354	      y: Math.round(
355	        (100 * data?.summary?.[0]?.succeeded) / data?.summary?.[0]?.total,
356	      ),
357	    },
358	    {
359	      x: t('Failed'),
360	      y: Math.round(
361	        (100 * data?.summary?.[0]?.failed) / data?.summary?.[0]?.total,
362	      ),
363	    },
364	    {
365	      x: t('Running'),
366	      y: Math.round(
367	        (100 * data?.summary?.[0]?.running) / data?.summary?.[0]?.total,
368	      ),
369	    },
370	    {
371	      x: t('Cancelled'),
372	      y: Math.round(
373	        (100 * data?.summary?.[0]?.cancelled) / data?.summary?.[0]?.total,
374	      ),
375	    },
376	    {
377	      x: t('Others'),
378	      y: Math.round(
379	        (100 * data?.summary?.[0]?.others) / data?.summary?.[0]?.total,
380	      ),
381	    },
382	  ];
383	
384	  const legendData = donutData.map((data) => {
385	    return {
386	      name: `${data.x}: ${isNaN(data.y) ? 0 : data.y}%`,
387	    };
388	  });
389	  return (
390	    <>
391	      <Card
392	        className={classNames('pipeline-overview__pipelinerun-status-card', {
393	          'card-border': bordered,
394	        })}
395	      >
396	        <CardTitle className="pipeline-overview__pipelinerun-status-card__title">
397	          <span>
398	            {t('PipelineRun status')}{' '}
399	            <Popover
400	              bodyContent={
401	                <>
402	                  {t(
403	                    'PipelineRun Status shows the % of PipelineRuns for various status like "Succeeded", "Failed", "Running", "Cancelled" and "Others". Here, Others includes statuses like "Started", "CreateRunFailed", "PipelineRunTimeout"',
404	                  )}
405	                </>
406	              }
407	            >
408	              <span
409	                role="button"
410	                aria-label={t('More info')}
411	                className="ocs-getting-started-grid__tooltip-icon"
412	              >
413	                <OutlinedQuestionCircleIcon />
414	              </span>
415	            </Popover>
416	          </span>
417	        </CardTitle>
418	        <CardBody className="pipeline-overview__pipelinerun-status-card__title">
419	          {pipelineRunsStatusError ? (
420	            <Alert
421	              variant="danger"
422	              isInline
423	              title={t('Unable to load PipelineRun status')}
424	              className="pf-v6-u-mb-md"
425	            />
426	          ) : (
427	            <Grid>
428	              <GridItem xl2={4} xl={12} lg={12} md={12} sm={12}>
429	                {loaded ? (
430	                  <div className="pipeline-overview__pipelinerun-status-card__donut-chart-div">
431	                    <ChartDonut
432	                      constrainToVisibleArea={true}
433	                      data={donutData}
434	                      labels={({ datum }) => `${datum.x}: ${datum.y}%`}
435	                      legendData={legendData}
436	                      colorScale={colorScale}
437	                      legendOrientation="vertical"
438	                      legendPosition="right"
439	                      padding={{
440	                        bottom: 30,
441	                        right: 140, // Adjusted to accommodate legend
442	                        top: 20,
443	                      }}
444	                      legendComponent={
445	                        <ChartLegend
446	                          data={legendData}
447	                          style={{
448	                            labels: {
449	                              fill: 'var(--pf-t--global--text--color--regular)',
450	                              fontSize: 14,
451	                            },
452	                          }}
453	                        />
454	                      }
455	                      subTitle={t('Succeeded')}
456	                      subTitleComponent={
457	                        <ChartLabel
458	                          style={{
459	                            fill: 'var(--pf-t--global--text--color--400)',
460	                            fontSize: 14,
461	                          }}
462	                        />
463	                      }
464	                      title={`${data?.summary?.[0]?.succeeded ?? 0}/${
465	                        data?.summary?.[0]?.total ?? 0
466	                      }`}
467	                      titleComponent={
468	                        <ChartLabel
469	                          style={{
470	                            fill: 'var(--pf-t--global--text--color--regular)',
471	                            fontSize: 24,
472	                          }}
473	                        />
474	                      }
475	                      width={350}
476	                    />
477	                  </div>
478	                ) : (
479	                  <LoadingInline />
480	                )}
481	              </GridItem>
482	              <GridItem xl2={8} xl={12} lg={12} md={12} sm={12}>
483	                <div className="pipeline-overview__pipelinerun-status-card__bar-chart-div">
484	                  {loaded ? (
485	                    <Chart
486	                      containerComponent={
487	                        <ChartVoronoiContainer
488	                          labels={({ datum }) => `${datum.name}: ${datum.y}%`}
489	                          constrainToVisibleArea
490	                        />
491	                      }
492	                      scale={{ x: 'time', y: 'linear' }}
493	                      domain={domainValue}
494	                      domainPadding={{ x: [30, 25] }}
495	                      height={200}
496	                      padding={{
497	                        top: 20,
498	                        bottom: 40,
499	                        right: 40,
500	                        left: 50,
501	                      }}
502	                      colorScale={colorScaleLineChart}
503	                      width={1000}
504	                    >
505	                      <ChartAxis
506	                        tickValues={tickValues}
507	                        style={xAxisStyle}
508	                        tickFormat={xTickFormat}
509	                        label={showLabel ? dayLabel : ''}
510	                      />
511	                      <ChartAxis
512	                        dependentAxis
513	                        tickFormat={(v) => `${v}%`}
514	                        style={yAxisStyle}
515	                      />
516	                      <ChartGroup>
517	                        <ChartLine data={chartDataSucceeded} />
518	                        <ChartLine data={chartDataFailed} />
519	                        <ChartLine data={chartDataCancelled} />
520	                        <ChartLine data={chartDataOthers} />
521	                      </ChartGroup>
522	                    </Chart>
523	                  ) : (
524	                    <LoadingInline />
525	                  )}
526	                </div>
527	              </GridItem>
528	            </Grid>
529	          )}
530	        </CardBody>
531	      </Card>
532	    </>
533	  );
534	};
535	
536	export default PipelinesRunsStatusCard;

