 72	    const s = data?.summary?.find((d) => {
 73	      const group_date = new Date(Number(d.group_value) * 1000);
 74	      if (type == 'hour') {
 75	        return group_date.getHours() === value;
 76	      }
 77	      if (type == 'day' || type == 'week') {
