 79	      }
 80	      if (type == 'month') {
 81	        return group_date.getMonth() === value.getMonth();
 82	      }
 83	    });
 84	    return {
 85	      x: value,
 86	      y: Math.round((100 * s?.[k]) / s?.total) || 0,
 87	      name: t(key),
 88	    };
 89	  });
 90	  return chartData;
 91	};
