 58	const getChartData = (
 59	  tickValues: number[] | Date[],
 60	  data: SummaryResponse,
 61	  key: string,
 62	  type: string,
 63	): {
 64	  x: number;
 65	  y: number;
 66	  name: string;
 67	}[] => {
 68	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 69	  const k = key.toLowerCase();
 70	  const chartData = tickValues?.map((value) => {
 71	    const s = data?.summary?.find((d) => {
 72	      const group_date = new Date(Number(d.group_value) * 1000);
 73	      if (type == 'hour') {
 74	        return group_date.getHours() === value;
 75	      }
 76	      if (type == 'day' || type == 'week') {
 77	        return group_date.toDateString() === new Date(value).toDateString();
 78	      }
 79	      if (type == 'month') {
 80	        return group_date.getMonth() === value.getMonth();
 81	      }
 82	    });
 83	    return {
 84	      x: value,
 85	      y: Math.round((100 * s?.[k]) / s?.total) || 0,
 86	      name: t(key),
 87	    };
 88	  });
 89	  return chartData;
 90	};
